INSERT INTO public.mind_coach_pathway_phases (id, pathway_name, phase_number, description, dynamic_prompt) VALUES
('family_conflict_and_dynamics_phase1', 'family_conflict_and_dynamics', 1, 'Step 1: Assess the family system, identifying roles, communication styles, and core conflicts.', 'You are currently guiding the user through Phase 1 of the ''family_conflict_and_dynamics'' pathway. Your goal for this phase is: Step 1: Assess the family system, identifying roles, communication styles, and core conflicts.'),
('family_conflict_and_dynamics_phase2', 'family_conflict_and_dynamics', 2, 'Step 2: Psychoeducate the user on enmeshment and healthy family boundaries.', 'You are currently guiding the user through Phase 2 of the ''family_conflict_and_dynamics'' pathway. Your goal for this phase is: Step 2: Psychoeducate the user on enmeshment and healthy family boundaries.'),
('family_conflict_and_dynamics_phase3', 'family_conflict_and_dynamics', 3, 'Step 3: Teach communication skills, such as assertive ''I'' statements and active listening.', 'You are currently guiding the user through Phase 3 of the ''family_conflict_and_dynamics'' pathway. Your goal for this phase is: Step 3: Teach communication skills, such as assertive ''I'' statements and active listening.'),
('family_conflict_and_dynamics_phase4', 'family_conflict_and_dynamics', 4, 'Step 4: Support the user in implementing new patterns and managing pushback from family members.', 'You are currently guiding the user through Phase 4 of the ''family_conflict_and_dynamics'' pathway. Your goal for this phase is: Step 4: Support the user in implementing new patterns and managing pushback from family members.'),
('crisis_intervention_and_suicide_prevention_phase1', 'crisis_intervention_and_suicide_prevention', 1, 'Step 1: Conduct an immediate risk assessment (intent, plan, means) and create a collaborative safety plan.', 'You are currently guiding the user through Phase 1 of the ''crisis_intervention_and_suicide_prevention'' pathway. Your goal for this phase is: Step 1: Conduct an immediate risk assessment (intent, plan, means) and create a collaborative safety plan.'),
